def show_dashboard(user_id, user):
    now = datetime.now()
    greeting = get_greeting()

    # Welcome Banner
    st.markdown(f"""
    <div class="gz-welcome">
        <h1>{greeting}, {user['display_name']}! 👋</h1>
        <p>{now.strftime('%A, %B %d, %Y')} &nbsp;·&nbsp; {now.strftime('%I:%M %p')}</p>
    </div>
    """, unsafe_allow_html=True)

    # ── STATS ROW ──
    inv_df = get_inventory(user_id)
    visits_df = get_visits(user_id, 30)
    recipes_df = get_recipes(user_id)

    low_stock = inv_df[inv_df['quantity'] <= inv_df['threshold']] if not inv_df.empty else pd.DataFrame()
    urgent = inv_df[inv_df['quantity'] <= inv_df['threshold']*0.5] if not inv_df.empty else pd.DataFrame()

    c1,c2,c3,c4,c5 = st.columns(5)
    stat_items = [
        (c1, str(len(inv_df)), "Items Tracked", "blue"),
        (c2, str(len(low_stock)), "Need Restocking", ""),
        (c3, str(len(urgent)), "Urgent", ""),
        (c4, str(len(visits_df)), "Trips This Month", "green"),
        (c5, str(len(recipes_df)), "Recipes", "green"),
    ]
    for col, val, label, cls in stat_items:
        with col:
            st.markdown(f"""
            <div class="gz-stat {f'gz-stat-{cls}' if cls else ''}">
                <div class="gz-stat-value">{val}</div>
                <div class="gz-stat-label">{label}</div>
            </div>
            """, unsafe_allow_html=True)

    st.markdown('<div style="height:1.5rem"></div>', unsafe_allow_html=True)

    # ── MAIN COLUMNS ──
    left, right = st.columns([1.5, 1])

    with left:
        # Grocery List
        section_title("🛒","Grocery List","Needs Restocking")
        if not low_stock.empty:
            for _, row in low_stock.iterrows():
                is_urgent = row['quantity'] <= row['threshold']*0.5
                badge = '<span class="gz-badge gz-badge-red">URGENT</span>' if is_urgent else '<span class="gz-badge gz-badge-yellow">LOW</span>'
                st.markdown(f"""
                <div class="gz-card" style="padding:0.75rem 1rem;">
                    <div style="display:flex;justify-content:space-between;align-items:center;">
                        <div>
                            <strong>{row['name']}</strong>
                            <span style="color:#94a3b8;font-size:0.8rem;margin-left:0.5rem;">
                                {row['quantity']:.1f} {row['unit']} left (need {row['threshold']:.1f} {row['unit']})
                            </span>
                        </div>
                        {badge}
                    </div>
                </div>
                """, unsafe_allow_html=True)
        else:
            insight_pill("All items are well stocked! 🎉", "success")

        # Visit Activity Chart
        st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)
        section_title("📊","Visit Activity","Last 30 Days")
        if not visits_df.empty:
            visits_df['date'] = pd.to_datetime(visits_df['visited_at']).dt.date
            daily = visits_df.groupby('date').size().reset_index(name='visits')
            try:
                import plotly.express as px
                fig = px.bar(daily, x='date', y='visits',
                            color_discrete_sequence=['#1d4ed8'])
                fig.update_layout(
                    paper_bgcolor='rgba(0,0,0,0)',
                    plot_bgcolor='rgba(0,0,0,0)',
                    margin=dict(l=0,r=0,t=10,b=0),
                    showlegend=False,
                    height=200,
                    xaxis=dict(showgrid=False),
                    yaxis=dict(showgrid=True, gridcolor='#f1f5f9')
                )
                st.plotly_chart(fig, use_container_width=True, config={'displayModeBar':False})
            except:
                st.bar_chart(daily.set_index('date')['visits'])
        else:
            st.markdown("""
            <div class="gz-card" style="text-align:center;color:#94a3b8;padding:2rem;">
                📍 No visits logged yet. Start planning trips!
            </div>
            """, unsafe_allow_html=True)

    with right:
        # Top Visits This Week
        section_title("🏆","Top Visits","This Week")
        visits_week = get_visits(user_id, 7)
        if not visits_week.empty:
            top = visits_week['location_name'].value_counts().head(5)
            medals = ["🥇","🥈","🥉","4️⃣","5️⃣"]
            for i,(name,cnt) in enumerate(top.items()):
                st.markdown(f"""
                <div style="display:flex;justify-content:space-between;align-items:center;
                            padding:0.5rem 0;border-bottom:1px solid #f1f5f9;">
                    <span style="font-weight:600;font-size:0.875rem;">{medals[i]} {name}</span>
                    <span class="gz-badge gz-badge-blue">{cnt} visits</span>
                </div>
                """, unsafe_allow_html=True)
        else:
            insight_pill("Log trips to see your top places!", "info")

        st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)

        # ML Insights
        section_title("🧠","AI Insights","Powered by GrihZen")
        if not low_stock.empty:
            for _, row in urgent.head(2).iterrows():
                insight_pill(f"{row['name']} is critically low!", "danger")
        if not inv_df.empty:
            # Nutrition insight
            total_cal = 0
            for _, row in inv_df.iterrows():
                total_cal += row['calories_per_100g'] * row['quantity'] * 0.01
            insight_pill(f"~{int(total_cal):,} kcal available in your pantry", "info")
        if not visits_week.empty:
            most_visited = visits_week['location_name'].value_counts().index[0]
            insight_pill(f"You visit {most_visited} most this week", "success")
        else:
            insight_pill("Plan your first trip to get AI insights!", "info")
            insight_pill("Add inventory to track nutrition automatically", "info")

        # Quick Actions
        st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)
        section_title("⚡","Quick Actions")
        col_a, col_b = st.columns(2)
        with col_a:
            if st.button("🗺️ Plan Trip", use_container_width=True):
                st.session_state.page = "Plan Trip"
                st.rerun()
        with col_b:
            if st.button("📦 Inventory", use_container_width=True):
                st.session_state.page = "Inventory"
                st.rerun()
        col_c, col_d = st.columns(2)
        with col_c:
            if st.button("🍳 Recipes", use_container_width=True):
                st.session_state.page = "Recipes"
                st.rerun()
        with col_d:
            if st.button("📊 Analytics", use_container_width=True):
                st.session_state.page = "Analytics"
                st.rerun()

        # Logout
        st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)
        if st.button("🚪 Sign Out", use_container_width=True, type="secondary"):
            for key in list(st.session_state.keys()):
                del st.session_state[key]
            st.rerun()

# ─── INVENTORY PAGE ───────────────────────────────────────────────────────────
def show_inventory(user_id):
    section_title("📦","Inventory Management","All Items")

    inv_df = get_inventory(user_id)

    # Add Item
    with st.expander("➕ Add New Item"):
        c1,c2,c3 = st.columns(3)
        with c1:
            new_item_id = st.text_input("Item ID (from nutrition DB)", placeholder="spinach")
            new_name = st.text_input("Display Name", placeholder="Spinach")
        with c2:
            new_qty = st.number_input("Quantity", min_value=0.0, value=100.0)
            new_unit = st.selectbox("Unit", ["g","kg","lbs","oz","cups","liters","ml","count"])
        with c3:
            new_thresh = st.number_input("Threshold (reorder point)", min_value=0.0, value=50.0)
            new_cat = st.selectbox("Category", ["vegetables","grains","protein","dairy","lentils","fats","spices","other"])

        col_known = st.columns(1)[0]
        with col_known:
            st.caption(f"📊 Known items with nutrition data: {', '.join(list(NUTRITION_DB.keys())[:10])}...")

        if st.button("➕ Add to Inventory", type="primary"):
            if new_item_id and new_name:
                add_inventory_item(user_id, new_item_id, new_name, new_qty, new_unit, new_thresh, new_cat)
                st.success(f"✅ Added {new_name}!")
                st.rerun()

    st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)

    if inv_df.empty:
        st.info("No items yet! Add your first item above.")
        return

    # Filter
    col_f1, col_f2 = st.columns([2,1])
    with col_f1:
        filter_cat = st.selectbox("Filter by Category", ["All"] + list(inv_df['category'].unique()))
    with col_f2:
        show_low = st.checkbox("Show Low Stock Only")

    display_df = inv_df.copy()
    if filter_cat != "All":
        display_df = display_df[display_df['category']==filter_cat]
    if show_low:
        display_df = display_df[display_df['quantity']<=display_df['threshold']]

    # Display items
    for _, row in display_df.iterrows():
        is_urgent = row['quantity'] <= row['threshold']*0.5
        is_low = row['quantity'] <= row['threshold']
        n = NUTRITION_DB.get(row['item_id'], {})

        with st.expander(
            f"{'🔴' if is_urgent else '🟡' if is_low else '✅'} {row['name']} — {row['quantity']:.1f} {row['unit']}"
        ):
            col1, col2, col3 = st.columns([2,1.5,1])

            with col1:
                st.markdown(f'<span class="gz-badge gz-badge-blue">{row["category"]}</span>', unsafe_allow_html=True)
                st.markdown('<div style="height:0.5rem"></div>', unsafe_allow_html=True)

                # Nutrition data
                if n:
                    st.markdown("**📊 Nutrition per 100g:**")
                    nutrition_bar("Calories", n.get("cal",0), 500, unit=" kcal")
                    nutrition_bar("Protein", n.get("pro",0), 30, color="green")
                    nutrition_bar("Carbs", n.get("carb",0), 50)
                    nutrition_bar("Fat", n.get("fat",0), 20)
                    nutrition_bar("Fiber", n.get("fib",0), 10, color="green")
                    if n.get("vit"):
                        st.caption(f"Vitamins & Minerals: {', '.join(n['vit'])}")
                else:
                    st.info("No nutrition data available for this item")

            with col2:
                new_qty = st.number_input("Update Qty", value=float(row['quantity']),
                                          key=f"qty_{row['item_id']}")
                new_thresh = st.number_input("Update Threshold", value=float(row['threshold']),
                                             key=f"thresh_{row['item_id']}")
                if st.button("💾 Save", key=f"save_{row['item_id']}"):
                    update_inventory_item(user_id, row['item_id'], new_qty, new_thresh)
                    st.success("Updated!")
                    st.rerun()

            with col3:
                # Stock status
                pct = min(100, int(row['quantity']/row['threshold']*100)) if row['threshold'] else 100
                if is_urgent:
                    st.markdown('<div class="gz-badge gz-badge-red" style="font-size:0.8rem;">🔴 URGENT</div>', unsafe_allow_html=True)
                elif is_low:
                    st.markdown('<div class="gz-badge gz-badge-yellow" style="font-size:0.8rem;">🟡 LOW</div>', unsafe_allow_html=True)
                else:
                    st.markdown('<div class="gz-badge gz-badge-green" style="font-size:0.8rem;">✅ OK</div>', unsafe_allow_html=True)
                st.progress(pct/100)
                st.caption(f"{pct}% of threshold")

                if st.button("🗑️ Delete", key=f"del_{row['item_id']}", type="secondary"):
                    delete_inventory_item(user_id, row['item_id'])
                    st.success("Deleted!")
                    st.rerun()

# ─── RECIPES PAGE ─────────────────────────────────────────────────────────────
def show_recipes(user_id):
    section_title("🍳","Recipe Manager","With Nutrition")

    recipes_df = get_recipes(user_id)
    inv_df = get_inventory(user_id)

    # Add Recipe
    with st.expander("➕ Add New Recipe"):
        c1,c2,c3 = st.columns(3)
        with c1:
            r_id = st.text_input("Recipe ID", placeholder="butter_chicken")
            r_name = st.text_input("Recipe Name", placeholder="Butter Chicken")
        with c2:
            r_cuisine = st.selectbox("Cuisine", ["Indian","South Indian","Italian","Chinese","Mexican","Fusion"])
            r_servings = st.number_input("Servings", min_value=1, value=4)
        with c3:
            r_prep = st.number_input("Prep time (hours)", min_value=0.0, value=0.5)
            r_cook = st.number_input("Cook time (minutes)", min_value=1, value=30)

        st.markdown("**Ingredients** (Item ID → grams):")
        r_ingredients = {}
        inv_ids = list(inv_df['item_id']) if not inv_df.empty else list(NUTRITION_DB.keys())[:10]
        for i in range(4):
            c_a, c_b = st.columns(2)
            with c_a:
                iid = st.selectbox(f"Ingredient {i+1}", ["(none)"]+inv_ids, key=f"ri_{i}")
            with c_b:
                iamt = st.number_input(f"Amount (g)", min_value=0.0, value=100.0, key=f"ra_{i}")
            if iid != "(none)" and iamt > 0:
                r_ingredients[iid] = iamt

        if st.button("➕ Save Recipe", type="primary"):
            if r_id and r_name and r_ingredients:
                nutrition = calculate_recipe_nutrition(r_ingredients)
                conn = get_db()
                c = conn.cursor()
                c.execute("""INSERT OR REPLACE INTO recipes
                    (user_id,recipe_id,name,ingredients,prep_hours,cook_minutes,cuisine,servings,nutrition_per_serving)
                    VALUES (?,?,?,?,?,?,?,?,?)""",
                    (user_id, r_id, r_name, json.dumps(r_ingredients),
                     r_prep, r_cook, r_cuisine, r_servings, json.dumps(nutrition)))
                conn.commit()
                conn.close()
                st.success("✅ Recipe saved!")
                st.rerun()

    st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)

    if recipes_df.empty:
        st.info("No recipes yet! Add your first recipe above.")
        return

    for _, row in recipes_df.iterrows():
        ingredients = json.loads(row['ingredients']) if row['ingredients'] else {}
        nutrition = json.loads(row['nutrition_per_serving']) if row['nutrition_per_serving'] else {}
        score = nutrition_score(nutrition, row['servings'])

        # Check availability
        available = 0
        total_ing = len(ingredients)
        for ing_id in ingredients:
            inv_match = inv_df[inv_df['item_id']==ing_id]
            if not inv_match.empty and inv_match.iloc[0]['quantity'] > 0:
                available += 1
        avail_pct = int(available/total_ing*100) if total_ing else 0

        with st.expander(f"🍽️ {row['name']} · {row['cuisine']} · ⭐ {score}/100"):
            col1, col2 = st.columns([1.5, 1])

            with col1:
                c_a, c_b, c_c = st.columns(3)
                with c_a:
                    st.metric("👥 Serves", row['servings'])
                with c_b:
                    st.metric("⏱️ Cook", f"{row['cook_minutes']}min")
                with c_c:
                    st.metric("🥗 Avail.", f"{avail_pct}%")

                st.markdown("**🥘 Ingredients:**")
                for ing_id, amt in ingredients.items():
                    n = NUTRITION_DB.get(ing_id, {})
                    name = n.get("name", ing_id)
                    inv_match = inv_df[inv_df['item_id']==ing_id]
                    in_stock = not inv_match.empty and inv_match.iloc[0]['quantity'] > 0
                    icon = "✅" if in_stock else "❌"
                    st.markdown(f"- {icon} {name}: **{amt:.0f}g**")

            with col2:
                # Nutrition
                st.markdown("**📊 Nutrition per serving:**")
                servings = max(1, row['servings'])
                nutrition_bar("Calories",
                    nutrition.get('cal',0)/servings, 700, unit=" kcal")
                nutrition_bar("Protein",
                    nutrition.get('pro',0)/servings, 50, color="green")
                nutrition_bar("Carbs",
                    nutrition.get('carb',0)/servings, 80)
                nutrition_bar("Fat",
                    nutrition.get('fat',0)/servings, 30)
                nutrition_bar("Fiber",
                    nutrition.get('fib',0)/servings, 10, color="green")

                if nutrition.get('vitamins'):
                    vitamins = nutrition['vitamins']
                    if isinstance(vitamins, list):
                        st.caption(f"🌟 Vitamins: {', '.join(vitamins[:5])}")

                # Nutrition score color
                score_color = COLORS['green_primary'] if score >= 70 else COLORS['warning'] if score >= 50 else COLORS['danger']
                st.markdown(f"""
                <div style="text-align:center;margin-top:1rem;">
                    <div style="font-family:'Outfit',sans-serif;font-size:2rem;font-weight:800;color:{score_color};">{score}</div>
                    <div style="font-size:0.75rem;color:#94a3b8;font-weight:600;">NUTRITION SCORE</div>
                </div>
                """, unsafe_allow_html=True)

# ─── TRIP PLANNER PAGE ────────────────────────────────────────────────────────
def show_trip_planner(user_id):
    section_title("🗺️","Trip Planner","Route Optimization")

    stores_df = get_stores(user_id)

    # Algorithm selector
    col_algo, col_start = st.columns([1,1])
    with col_algo:
        algorithm = st.selectbox("🧠 Algorithm", [
            "Genetic Algorithm (Best Quality)",
            "Simulated Annealing (Good & Fast)",
            "2-opt (Quick & Efficient)",
            "Nearest Neighbor (Fastest)",
            "Brute Force (Exact, n≤8)",
            "Compare All Algorithms",
        ])
    with col_start:
        start_from = st.radio("📍 Start From", ["Home","Work"], horizontal=True)

    start_loc = HOME if start_from == "Home" else WORK

    # Store selection
    section_title("🛒","Select Destinations")
    selected = []
    if not stores_df.empty:
        for _, s in stores_df.iterrows():
            dist = haversine(start_loc["lat"], start_loc["lng"], s['lat'], s['lng'])
            t = estimate_time(dist)
            if st.checkbox(
                f"🏪 **{s['name']}** — {s['address']} ({t} min from {start_from}, {s['avg_visit_duration']} min visit)",
                key=f"sel_{s['store_id']}"
            ):
                selected.append({
                    "id": s['store_id'], "name": s['name'],
                    "lat": s['lat'], "lng": s['lng'],
                    "visit_time": s['avg_visit_duration']
                })
    else:
        st.info("Add stores in the Locations page first!")

    end_option = st.radio("🏁 End At", ["Home","Work","Last Stop"], horizontal=True)
    end_loc = HOME if end_option=="Home" else (WORK if end_option=="Work" else None)

    if st.button("🚗 Optimize Route", type="primary", use_container_width=True):
        if not selected:
            st.warning("Select at least one destination!")
            return

        algo_name = algorithm.split(" (")[0]
        stops = [{k:v for k,v in s.items()} for s in selected]

        if "Compare All" in algorithm:
            st.markdown("---")
            section_title("🔬","Algorithm Comparison","MS-Level Analysis")

            results = []
            algos = [
                ("Nearest Neighbor", nearest_neighbor_route, "O(n²)", "Greedy"),
                ("2-opt", two_opt_route, "O(n²) iters", "Local Search"),
                ("Simulated Annealing", simulated_annealing_route, "O(n·T)", "Probabilistic"),
                ("Genetic Algorithm", genetic_route, "O(n·gen)", "Evolutionary"),
            ]
            if len(stops) <= 7:
                algos.insert(0, ("Brute Force", brute_force_route, "O(n!)", "Exact"))

            for name, func, complexity, type_ in algos:
                route, dist, ms = func(stops, start_loc, end_loc)
                visit_t = sum(s['visit_time'] for s in stops)
                total_t = estimate_time(dist) + visit_t
                results.append({
                    "Algorithm": name,
                    "Distance": f"{dist:.2f} mi",
                    "Drive Time": f"{estimate_time(dist)} min",
                    "Total Time": f"{total_t} min",
                    "Compute": f"{ms:.1f} ms",
                    "Complexity": complexity,
                    "Type": type_,
                })

            # Show table
            st.markdown("""
            <table class="gz-table">
            <thead><tr>
                <th>Algorithm</th><th>Type</th><th>Complexity</th>
                <th>Distance</th><th>Total Time</th><th>Compute Time</th>
            </tr></thead>
            <tbody>
            """, unsafe_allow_html=True)

            best_time = min(int(r['Total Time'].replace(' min','')) for r in results)
            for r in results:
                t_val = int(r['Total Time'].replace(' min',''))
                is_best = t_val == best_time
                highlight = f"background:{COLORS['blue_pale']};" if is_best else ""
                st.markdown(f"""
                <tr style="{highlight}">
                    <td><strong>{r['Algorithm']}</strong>{'  🏆' if is_best else ''}</td>
                    <td><span class="gz-badge gz-badge-blue">{r['Type']}</span></td>
                    <td><code>{r['Complexity']}</code></td>
                    <td>{r['Distance']}</td>
                    <td><strong>{r['Total Time']}</strong></td>
                    <td>{r['Compute']}</td>
                </tr>
                """, unsafe_allow_html=True)
            st.markdown("</tbody></table>", unsafe_allow_html=True)

            insight_pill("Genetic Algorithm balances quality and speed for most route sizes", "success")
            insight_pill("Brute Force is exact but only feasible for ≤8 stops (n! grows fast!)", "warning")

        else:
            # Single algorithm
            algo_map = {
                "Genetic Algorithm": genetic_route,
                "Simulated Annealing": simulated_annealing_route,
                "2-opt": two_opt_route,
                "Nearest Neighbor": nearest_neighbor_route,
                "Brute Force": brute_force_route,
            }
            func = algo_map.get(algo_name, genetic_route)

            # Get top 3 routes
            st.markdown("---")
            section_title("📊","Top 3 Route Options")

            all_routes = []
            for _ in range(20):
                route, dist, ms = func(stops, start_loc, end_loc)
                visit_t = sum(s['visit_time'] for s in stops)
                total_t = estimate_time(dist) + visit_t
                # Check if duplicate
                route_key = "→".join(r['name'] for r in route)
                if not any(r['key']==route_key for r in all_routes):
                    all_routes.append({'route':route,'dist':dist,'total_t':total_t,'ms':ms,'key':route_key})
                if len(all_routes) >= 3:
                    break

            all_routes.sort(key=lambda x: x['total_t'])

            medals = ["🥇","🥈","🥉"]
            for i, r in enumerate(all_routes[:3]):
                route_str = " → ".join(loc['name'] for loc in r['route'])
                diff = r['total_t'] - all_routes[0]['total_t']
                diff_str = f"Best Route!" if i==0 else f"+{diff} min"

                if i==0:
                    st.success(f"{medals[i]} **{diff_str}** — Total: **{r['total_t']} min** | {route_str}")
                elif i==1:
                    st.info(f"{medals[i]} **{diff_str}** — Total: **{r['total_t']} min** | {route_str}")
                else:
                    st.warning(f"{medals[i]} **{diff_str}** — Total: **{r['total_t']} min** | {route_str}")

                with st.expander(f"Route {i+1} Details"):
                    for j,loc in enumerate(r['route']):
                        if j==0: st.write(f"🚀 **START:** {loc['name']}")
                        elif j==len(r['route'])-1: st.write(f"🏁 **END:** {loc['name']}")
                        else:
                            vt = next((s['visit_time'] for s in stops if s['name']==loc['name']),0)
                            st.write(f"📍 **Stop {j}:** {loc['name']} (~{vt} min visit)")
                        if j < len(r['route'])-1:
                            next_loc = r['route'][j+1]
                            d = haversine(loc['lat'],loc['lng'],next_loc['lat'],next_loc['lng'])
                            st.caption(f"    ↓ {estimate_time(d)} min drive ({d:.1f} mi)")

                    c1,c2,c3 = st.columns(3)
                    with c1: st.metric("📏 Distance", f"{r['dist']:.1f} mi")
                    with c2: st.metric("⏱️ Total Time", f"{r['total_t']} min")
                    with c3:
                        eta = datetime.now() + timedelta(minutes=r['total_t'])
                        st.metric("🏁 ETA", eta.strftime("%I:%M %p"))

            # Complete trip button
            st.markdown("---")
            col_a, col_b = st.columns(2)
            with col_a:
                if st.button("✅ Mark Trip Complete", type="primary", use_container_width=True):
                    for s in selected:
                        log_visit(user_id, s['id'], 'store', s['name'])
                    st.success(f"✅ Logged {len(selected)} visits!")
                    st.balloons()

