def show_locations(user_id):
    section_title("🏢","Manage Locations","Stores & Places")
    stores_df = get_stores(user_id)

    visits_week = get_visits(user_id, 7)
    visits_month = get_visits(user_id, 30)

    with st.expander("➕ Add New Store"):
        with st.form("add_store_form"):
            c1,c2 = st.columns(2)
            with c1:
                sid = st.text_input("Store ID", placeholder="costco")
                sname = st.text_input("Store Name", placeholder="Costco")
                saddr = st.text_input("Address")
            with c2:
                slat = st.number_input("Latitude", format="%.6f", value=32.7767)
                slng = st.number_input("Longitude", format="%.6f", value=-96.7970)
                savg = st.number_input("Avg Visit (min)", min_value=5, value=30)
            c3,c4 = st.columns(2)
            with c3:
                sprice = st.slider("Price Rating", 1.0, 5.0, 3.0, 0.5)
            with c4:
                squal = st.slider("Quality Rating", 1.0, 5.0, 4.0, 0.5)
            sgood = st.text_input("Good For (comma separated)", placeholder="groceries, produce")
            if st.form_submit_button("➕ Add Store", type="primary"):
                if sid and sname:
                    add_store(user_id, sid, sname, saddr, slat, slng,
                              [x.strip() for x in sgood.split(',') if x.strip()],
                              savg, sprice, squal)
                    st.success(f"✅ Added {sname}!")
                    st.rerun()

    st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)

    if stores_df.empty:
        st.info("No stores added yet!")
        return

    for _, s in stores_df.iterrows():
        week_cnt = len(visits_week[visits_week['location_id']==s['store_id']]) if not visits_week.empty else 0
        month_cnt = len(visits_month[visits_month['location_id']==s['store_id']]) if not visits_month.empty else 0
        good_for = json.loads(s['good_for']) if s['good_for'] else []

        with st.expander(f"🏪 {s['name']} — {s['address']}"):
            c1,c2,c3 = st.columns([2,1,1])
            with c1:
                st.markdown(f"**📍 Coords:** {s['lat']:.4f}, {s['lng']:.4f}")
                if good_for:
                    badges = " ".join(f'<span class="gz-badge gz-badge-blue">{g}</span>' for g in good_for)
                    st.markdown(f"**Good for:** {badges}", unsafe_allow_html=True)
                st.markdown(f"**Avg Visit:** {s['avg_visit_duration']} min | **Price:** {s['price_rating']}/5 | **Quality:** {s['quality_rating']}/5")
            with c2:
                st.markdown(f"""
                <div class="gz-stat" style="text-align:center;">
                    <div class="gz-stat-value gz-stat-blue" style="font-size:1.5rem;">{week_cnt}</div>
                    <div class="gz-stat-label">This Week</div>
                </div>
                """, unsafe_allow_html=True)
            with c3:
                st.markdown(f"""
                <div class="gz-stat gz-stat-green" style="text-align:center;">
                    <div class="gz-stat-value" style="font-size:1.5rem;">{month_cnt}</div>
                    <div class="gz-stat-label">This Month</div>
                </div>
                """, unsafe_allow_html=True)

            if st.button(f"🗑️ Delete {s['name']}", key=f"delst_{s['store_id']}", type="secondary"):
                delete_store(user_id, s['store_id'])
                st.success("Deleted!")
                st.rerun()

