def show_analytics(user_id):
    section_title("📊","Analytics & Insights","Your Patterns")

    visits_all = get_visits(user_id, 365)
    visits_week = get_visits(user_id, 7)
    visits_month = get_visits(user_id, 30)
    inv_df = get_inventory(user_id)

    # Stats
    c1,c2,c3 = st.columns(3)
    with c1:
        st.markdown(f"""
        <div class="gz-stat gz-stat-blue">
            <div class="gz-stat-value">{len(visits_all)}</div>
            <div class="gz-stat-label">Total Visits</div>
        </div>""", unsafe_allow_html=True)
    with c2:
        st.markdown(f"""
        <div class="gz-stat">
            <div class="gz-stat-value">{len(visits_week)}</div>
            <div class="gz-stat-label">This Week</div>
        </div>""", unsafe_allow_html=True)
    with c3:
        st.markdown(f"""
        <div class="gz-stat gz-stat-green">
            <div class="gz-stat-value">{len(visits_month)}</div>
            <div class="gz-stat-label">This Month</div>
        </div>""", unsafe_allow_html=True)

    st.markdown('<div style="height:1rem"></div>', unsafe_allow_html=True)

    col_left, col_right = st.columns(2)

    with col_left:
        section_title("🏆","Top Locations","All Time")
        if not visits_all.empty:
            top = visits_all['location_name'].value_counts().head(8)
            try:
                import plotly.express as px
                fig = px.bar(x=top.values, y=top.index, orientation='h',
                            color=top.values, color_continuous_scale='Blues')
                fig.update_layout(paper_bgcolor='rgba(0,0,0,0)',
                                  plot_bgcolor='rgba(0,0,0,0)',
                                  height=300, margin=dict(l=0,r=0,t=10,b=0),
                                  showlegend=False, coloraxis_showscale=False)
                st.plotly_chart(fig, use_container_width=True, config={'displayModeBar':False})
            except:
                st.bar_chart(top)
        else:
            st.info("No visits yet. Log your first trip!")

    with col_right:
        section_title("🥗","Nutrition Overview","Pantry Analysis")
        if not inv_df.empty:
            total_cal = sum(row['calories_per_100g']*row['quantity']*0.01 for _,row in inv_df.iterrows())
            total_pro = sum(row['protein_per_100g']*row['quantity']*0.01 for _,row in inv_df.iterrows())
            total_carb = sum(row['carbs_per_100g']*row['quantity']*0.01 for _,row in inv_df.iterrows())
            total_fat = sum(row['fat_per_100g']*row['quantity']*0.01 for _,row in inv_df.iterrows())

            nutrition_bar("Total Calories in Pantry", total_cal, 10000, unit=" kcal")
            nutrition_bar("Total Protein", total_pro, 500, color="green")
            nutrition_bar("Total Carbs", total_carb, 1500)
            nutrition_bar("Total Fat", total_fat, 400)

            # Insights
            st.markdown('<div style="height:0.5rem"></div>', unsafe_allow_html=True)
            if total_cal > 5000:
                insight_pill("Good pantry stock! Enough food for several days", "success")
            else:
                insight_pill("Pantry is running low. Time to restock!", "warning")
        else:
            st.info("Add inventory items to see nutrition analysis")

    # Manual Visit Log
    st.markdown("---")
    section_title("📝","Log a Visit Manually")
    with st.form("manual_log"):
        c1,c2,c3 = st.columns(3)
        with c1:
            log_date = st.date_input("Date", datetime.now())
        with c2:
            stores_df = get_stores(user_id)
            store_options = {s['name']: s['store_id'] for _,s in stores_df.iterrows()} if not stores_df.empty else {}
            store_name = st.selectbox("Location", list(store_options.keys()) or ["No stores yet"])
        with c3:
            st.markdown('<div style="height:1.7rem"></div>', unsafe_allow_html=True)
            submit = st.form_submit_button("📝 Log Visit", type="primary")
        if submit and store_options and store_name in store_options:
            log_visit(user_id, store_options[store_name], 'store', store_name)
            st.success("✅ Visit logged!")
            st.rerun()

    # Recent visits
    section_title("🕐","Recent Visit History")
    if not visits_all.empty:
        recent = visits_all.sort_values('visited_at', ascending=False).head(10)
        for _,v in recent.iterrows():
            dt = pd.to_datetime(v['visited_at'])
            st.markdown(f"""
            <div style="display:flex;justify-content:space-between;align-items:center;
                        padding:0.6rem 0;border-bottom:1px solid #f1f5f9;">
                <span style="font-weight:600;">📍 {v['location_name']}</span>
                <span style="color:#94a3b8;font-size:0.8rem;">{dt.strftime('%b %d, %Y at %I:%M %p')}</span>
            </div>
            """, unsafe_allow_html=True)
    else:
        st.info("No visits logged yet!")

