# ─── MAIN APP ─────────────────────────────────────────────────────────────────
def main():
    init_db()
    inject_css()

    # ── NOT LOGGED IN ──
    if not st.session_state.get("logged_in"):
        show_login()
        return

    # ── LOGGED IN ──
    user_id = st.session_state.user_id
    user = get_user(user_id)
    if not user:
        st.error("Session expired. Please log in again.")
        st.session_state.logged_in = False
        st.rerun()
        return

    # Navbar
    render_navbar(user)

    # Tabs
    st.markdown('<div style="height:0.25rem"></div>', unsafe_allow_html=True)
    render_tabs()

    # Content
    st.markdown('<div style="padding:1.5rem 2rem;">', unsafe_allow_html=True)

    page = st.session_state.get("page","Dashboard")

    if page == "Dashboard":
        show_dashboard(user_id, user)
    elif page == "Inventory":
        show_inventory(user_id)
    elif page == "Recipes":
        show_recipes(user_id)
    elif page == "Plan Trip":
        show_trip_planner(user_id)
    elif page == "Locations":
        show_locations(user_id)
    elif page == "Analytics":
        show_analytics(user_id)
    elif page == "Settings":
        show_settings(user_id, user)

    st.markdown('</div>', unsafe_allow_html=True)

    # Footer
    st.markdown(f"""
    <div class="gz-footer" style="display:flex;align-items:center;justify-content:center;gap:0.75rem;">
        <img src="data:image/png;base64," style="height:24px;border-radius:4px;" />
        GrihZen v2.0 · Your Zen for Home Life · {datetime.now().strftime('%Y')} · Built with ❤️ and Data Science
    </div>
    """, unsafe_allow_html=True)

if __name__ == "__main__":
    main()
